410		private async backfillPullRequests({
411			installationDbId,
412			repoDbId,
413			repoFullName,
414			owner,
415			repo,
416			token,
417		}: {
418			installationDbId: string;
419			repoDbId: string;
420			repoFullName: string;
421			owner: string;
422			repo: string;
423			token: string;
424		}): Promise<void> {
425			let page = 1;
426			const perPage = 100;
427			while (true) {
428				const { data: prs } = await this.httpService.axiosRef.get<IGithubApiPullRequest[]>(
429					`https://api.github.com/repos/${owner}/${repo}/pulls`,
430					{
431						headers: {
432							Authorization: `token ${token}`,
433							Accept: 'application/vnd.github+json',
434							'X-GitHub-Api-Version': '2022-11-28',
435						},
436						params: { state: 'all', per_page: perPage, page },
437					},
438				);
439				if (prs.length === 0) break;
440				for (const pr of prs) {
441					await this.contributorModel.upsert({
442						data: {
443							installation_id: installationDbId,
444							github_user_id: pr.user.id,
445							github_login: pr.user.login,
446						},
447					});
448					const saved = await this.pullRequestModel.upsert({
449						data: {
450							installation_id: installationDbId,
451							repo_id: repoDbId,
452							github_pr_id: pr.id,
453							pr_number: pr.number,
454							title: pr.title,
455							state: pr.state as GithubPRState,
456							author_login: pr.user.login,
457							draft: pr.draft,
458							merged: pr.merged,
459							additions: pr.additions,
460							deletions: pr.deletions,
461							changed_files: pr.changed_files,
462							commits_count: pr.commits,
463							opened_at: new Date(pr.created_at),
464							merged_at: pr.merged_at ? new Date(pr.merged_at) : null,
465							closed_at: pr.closed_at ? new Date(pr.closed_at) : null,
466						},
467					});
468					await this.backfillPrReviews({ installationDbId, prDbId: saved._id, owner, repo, prNumber: pr.number, token });
469					await this.backfillPrReviewComments({ installationDbId, prDbId: saved._id, owner, repo, prNumber: pr.number, token });
470				}
471				if (prs.length < perPage) break;
472				page++;
473			}
474			this.logger.debug(`Backfilled PRs for ${repoFullName}`);
475		}
