16	interface IInstallStateValue {
17		companyId: string;
18		userId: string;
19	}
20	
21	const STATE_TTL_MS = 5 * 60 * 1000;
22	
23	@Injectable()
24	export class GithubInstallService {
25		private readonly logger = new Logger(GithubInstallService.name);
26	
27		constructor(
28			private readonly configService: EnvConfigService,
29			private readonly cacheService: CacheService,
30			private readonly githubAppService: GithubAppService,
31			private readonly githubInstallationModel: GithubInstallationModel,
32			private readonly githubRepoModel: GithubRepoModel,
33			private readonly backfillService: GithubBackfillService,
34		) {}
35	
36		async initiateConnect({
37			companyId,
38			userId,
39		}: {
40			companyId: string;
41			userId: string;
42		}): Promise<string> {
43			const state = randomUUID();
44	
45			await this.cacheService.set({
46				namespace: Namespaces.GITHUB_INSTALL_STATE,
47				key: state,
48				value: { companyId, userId } satisfies IInstallStateValue,
49				ttl: STATE_TTL_MS,
50			});
51	
52			const appName = this.configService.get<string>({ key: GITHUB_APP_NAME });
53			return `https://github.com/apps/${appName}/installations/new?state=${state}`;
54		}
55	
56		async handleCallback({
57			installationId,
58			state,
59		}: {
60			installationId: number;
61			state: string;
62		}): Promise<IGithubInstallationBase> {
63			const stateData = await this.cacheService.get<IInstallStateValue>({
64				namespace: Namespaces.GITHUB_INSTALL_STATE,
65				key: state,
66			});
67	
68			if (!stateData) {
69				throw new BadRequestException('Invalid or expired state token');
70			}
71	
72			await this.cacheService.deleteOne({
73				namespace: Namespaces.GITHUB_INSTALL_STATE,
74				key: state,
75			});
76	
77			const githubInstall = await this.githubAppService.getInstallation({ installationId });
78	
79			const installation = await this.githubInstallationModel.create({
80				data: {
81					company_id: stateData.companyId,
82					installation_id: installationId,
83					org_login: githubInstall.account.login,
84					org_id: githubInstall.account.id,
85				},
86			});
87	
88			void this.syncRepos({
